using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal — happy path (DataRow)

    [TestMethod]
    [DataRow(10.0, 1, 0.0, 10.0, DisplayName = "Single item, no tax")]
    [DataRow(10.0, 2, 0.0, 20.0, DisplayName = "Multiple items, no tax")]
    [DataRow(10.0, 1, 0.10, 11.0, DisplayName = "Single item, 10% tax")]
    [DataRow(25.0, 4, 0.20, 120.0, DisplayName = "Multiple items, 20% tax")]
    [DataRow(0.0, 5, 0.10, 0.0, DisplayName = "Zero unit price")]
    [DataRow(10.0, 0, 0.10, 0.0, DisplayName = "Zero quantity")]
    [DataRow(0.0, 0, 0.0, 0.0, DisplayName = "All zeros")]
    [DataRow(100.0, 1, 1.0, 200.0, DisplayName = "Maximum tax rate (100%)")]
    // DataRow doesn't support decimal literals; doubles convert cleanly for these values.
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    #endregion

    #region CalculateTotal — validation (DynamicData)

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs), DynamicDataSourceType.Method,
        DynamicDataDisplayName = nameof(GetCalculateTotalDisplayName))]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRangeException(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    private static IEnumerable<object[]> InvalidCalculateTotalInputs()
    {
        yield return [-1m, 1, 0.1m, "unitPrice"];
        yield return [10m, -1, 0.1m, "quantity"];
        yield return [10m, 1, -0.01m, "taxRate"];
        yield return [10m, 1, 1.01m, "taxRate"];
    }

    public static string GetCalculateTotalDisplayName(MethodInfo _, object[] data) =>
        $"unitPrice={data[0]}, qty={data[1]}, tax={data[2]} → throws on '{data[3]}'";

    #endregion

    #region ApplyDiscount — happy path (DataRow)

    [TestMethod]
    [DataRow(100.0, 0.0, 100.0, DisplayName = "No discount")]
    [DataRow(100.0, 10.0, 90.0, DisplayName = "10% discount")]
    [DataRow(100.0, 50.0, 50.0, DisplayName = "50% discount")]
    [DataRow(100.0, 100.0, 0.0, DisplayName = "Full discount")]
    [DataRow(200.0, 25.0, 150.0, DisplayName = "25% off $200")]
    [DataRow(0.0, 50.0, 0.0, DisplayName = "Zero price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var result = _calculator.ApplyDiscount(
            (decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, result);
    }

    #endregion

    #region ApplyDiscount — boundary / precision (DynamicData property)

    [TestMethod]
    [DynamicData(nameof(DiscountPrecisionCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_WithFractionalValues_ReturnsExpectedResult(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> DiscountPrecisionCases =>
    [
        [99.99m, 15m, 84.9915m],
        [49.95m, 33.33m, 33.3016650m],
        [1000m, 0.01m, 999.9000m],
    ];

    #endregion

    #region ApplyDiscount — validation (DataRow)

    [TestMethod]
    [DataRow(100.0, -1.0, DisplayName = "Negative discount")]
    [DataRow(100.0, -0.01, DisplayName = "Slightly negative discount")]
    [DataRow(100.0, 100.01, DisplayName = "Discount just over 100%")]
    [DataRow(100.0, 200.0, DisplayName = "Discount far over 100%")]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRangeException(
        double price, double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }

    #endregion

    #region FormatPrice (DynamicData)

    [TestMethod]
    [DynamicData(nameof(FormatPriceCases), DynamicDataSourceType.Method)]
    public void FormatPrice_WithVariousInputs_ReturnsFormattedString(
        decimal price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice(price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> FormatPriceCases()
    {
        yield return [10.5m, "$", "$10.50"];
        yield return [0m, "$", "$0.00"];
        yield return [1234.5678m, "€", "€1234.57"];
        yield return [99.999m, "£", "£100.00"];
    }

    [TestMethod]
    public void FormatPrice_WithDefaultCurrency_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.AreEqual("$42.00", result);
    }

    #endregion
}

