16. 
17.     [TestMethod]
18.     [DataRow(10.0, 1, 0.0, 10.0, DisplayName = "Single item, no tax")]
19.     [DataRow(10.0, 2, 0.0, 20.0, DisplayName = "Multiple items, no tax")]
20.     [DataRow(10.0, 1, 0.10, 11.0, DisplayName = "Single item, 10% tax")]
21.     [DataRow(25.0, 4, 0.20, 120.0, DisplayName = "Multiple items, 20% tax")]
22.     [DataRow(0.0, 5, 0.10, 0.0, DisplayName = "Zero unit price")]
23.     [DataRow(10.0, 0, 0.10, 0.0, DisplayName = "Zero quantity")]
24.     [DataRow(0.0, 0, 0.0, 0.0, DisplayName = "All zeros")]
25.     [DataRow(100.0, 1, 1.0, 200.0, DisplayName = "Maximum tax rate (100%)")]
26.     // DataRow doesn't support decimal literals; doubles convert cleanly for these values.
27.     public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
28.         double unitPrice, int quantity, double taxRate, double expectedTotal)
29.     {
30.         var result = _calculator.CalculateTotal(
31.             (decimal)unitPrice, quantity, (decimal)taxRate);
32. 
33.         Assert.AreEqual((decimal)expectedTotal, result);
34.     }
35. 
36.     #endregion
37. 
38.     #region CalculateTotal — validation (DynamicData)
39. 
40.     [TestMethod]
41.     [DynamicData(nameof(InvalidCalculateTotalInputs), DynamicDataSourceType.Method,
42.         DynamicDataDisplayName = nameof(GetCalculateTotalDisplayName))]
43.     public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRangeException(
44.         decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)
45.     {
46.         var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
47.             () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
48. 
49.         Assert.AreEqual(expectedParamName, ex.ParamName);
50.     }
51. 
52.     private static IEnumerable<object[]> InvalidCalculateTotalInputs()
53.     {
54.         yield return [-1m, 1, 0.1m, "unitPrice"];
