70.     [DataRow(100.0, 50.0, 50.0, DisplayName = "50% discount")]
71.     [DataRow(100.0, 100.0, 0.0, DisplayName = "Full discount")]
72.     [DataRow(200.0, 25.0, 150.0, DisplayName = "25% off $200")]
73.     [DataRow(0.0, 50.0, 0.0, DisplayName = "Zero price")]
74.     public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
75.         double price, double discountPercent, double expectedPrice)
76.     {
77.         var result = _calculator.ApplyDiscount(
78.             (decimal)price, (decimal)discountPercent);
79. 
