81.     }
82. 
83.     #endregion
84. 
85.     #region ApplyDiscount — boundary / precision (DynamicData property)
86. 
87.     [TestMethod]
88.     [DynamicData(nameof(DiscountPrecisionCases), DynamicDataSourceType.Property)]
89.     public void ApplyDiscount_WithFractionalValues_ReturnsExpectedResult(
