91.     {
92.         var result = _calculator.ApplyDiscount(price, discountPercent);
93. 
94.         Assert.AreEqual(expected, result);
95.     }
96. 
97.     public static IEnumerable<object[]> DiscountPrecisionCases =>
98.     [
99.         [99.99m, 15m, 84.9915m],
100.         [49.95m, 33.33m, 33.3016650m],
101.         [1000m, 0.01m, 999.9000m],
102.     ];
103. 
104.     #endregion
105. 
106.     #region ApplyDiscount — validation (DataRow)
107. 
108.     [TestMethod]
109.     [DataRow(100.0, -1.0, DisplayName = "Negative discount")]
110.     [DataRow(100.0, -0.01, DisplayName = "Slightly negative discount")]
111.     [DataRow(100.0, 100.01, DisplayName = "Discount just over 100%")]
112.     [DataRow(100.0, 200.0, DisplayName = "Discount far over 100%")]
113.     public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRangeException(
114.         double price, double discountPercent)
115.     {
116.         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
117.             () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
118.     }
119. 
120.     #endregion
121. 
122.     #region FormatPrice (DynamicData)
123. 
124.     [TestMethod]
125.     [DynamicData(nameof(FormatPriceCases), DynamicDataSourceType.Method)]
126.     public void FormatPrice_WithVariousInputs_ReturnsFormattedString(
127.         decimal price, string currencySymbol, string expected)
128.     {
129.         var result = _calculator.FormatPrice(price, currencySymbol);
130. 
131.         Assert.AreEqual(expected, result);
132.     }
133. 
134.     private static IEnumerable<object[]> FormatPriceCases()
135.     {
136.         yield return [10.5m, "$", "$10.50"];
137.         yield return [0m, "$", "$0.00"];
138.         yield return [1234.5678m, "€", "€1234.57"];
139.         yield return [99.999m, "£", "£100.00"];
140.     }
141. 
