143.     public void FormatPrice_WithDefaultCurrency_UsesDollarSign()
144.     {
145.         var result = _calculator.FormatPrice(42.00m);
146. 
147.         Assert.AreEqual("$42.00", result);
148.     }
149. 
150.     #endregion
151. }
