     private static IEnumerable<object[]> FormatPriceCases()
     {
         yield return [10.5m, "$", "$10.50"];
         yield return [0m, "$", "$0.00"];
         yield return [1234.5678m, "€", "€1234.57"];
         yield return [99.999m, "£", "£100.00"];
     }

     [TestMethod]
     public void FormatPrice_WithDefaultCurrency_UsesDollarSign()
     {
         var result = _calculator.FormatPrice(42.00m);

         Assert.AreEqual("$42.00", result);
     }

